// // This module implements a 16-bit SRAM cell with read and write capabilities.
// Inputs:
// - address: 4-bit address to select one of the 16 memory locations.
// - data_in: 16-bit input data for writing.
// - write_enable: signal to disable writing to the selected memory location.
// - read_enable: signal to disable reading from the selected memory location.

// Outputs:
// - data_out: 16-bit output data upon reading from the selected memory location.

// When write_enable is low, the data_in should be written to the memory location specified by address.
// When read_enable is low, the data_out should reflect the data stored at the memory location specified by address.
// Ensure that both read and write operations can occur simultaneously.
module sram_cell (
    input [3:0] address,
    input [15:0] data_in,
    input write_enable,
    input read_enable,
    output reg [15:0] data_out
);
    reg [15:0] memory [0:15]; // 16 memory locations, each 16 bits wide

    always @(*) begin
        if (write_enable) begin
            memory[address] <= data_in; // Write data to selected address
        end
    end

    always @(*) begin
        if (read_enable) begin
            data_out <= memory[address]; // Read data from selected address
        end else begin
            data_out <= 16'bz; // High impedance when not reading
        end
    end
endmodule

